                      <select
                        value={selectedOrder.payment_status}
                        onChange={e => updatePaymentStatus(selectedOrder.id, e.target.value)}
                        className={`${getPaymentBadge(selectedOrder.payment_status)} cursor-pointer appearance-none pr-6 border-0`}
