  }

  const body = await req.json()
  const { productId, quantity = 1 } = body

  if (!productId) {
    return NextResponse.json({ error: 'Product ID is required' }, { status: 400 })
  }

  if (typeof quantity !== 'number' || quantity < 1) {
    return NextResponse.json({ error: 'Quantity must be a positive number' }, { status: 400 })
  }

  try {
    const { data: product, error: productError } = await supabase
      .from('products')
      .select('id, stock, is_hidden')
      .eq('id', productId)
      .single()

    if (productError || !product) {
      return NextResponse.json({ error: 'Product not found' }, { status: 404 })
    }

    if (product.is_hidden) {
      return NextResponse.json({ error: 'Product is not available' }, { status: 400 })
    }

    const { data: existingItem } = await supabase
      .from('user_cart')
      .select('id, quantity')
      .eq('user_id', userId)
      .eq('product_id', productId)
      .single()

    if (existingItem) {
      const newQuantity = existingItem.quantity + quantity

      if (product.stock > 0 && newQuantity > product.stock) {
        return NextResponse.json({ error: 'Not enough stock available' }, { status: 400 })
      }

      const { error: updateError } = await supabase
        .from('user_cart')
        .update({ quantity: newQuantity })
        .eq('id', existingItem.id)

      if (updateError) {
        return NextResponse.json({ error: 'Failed to update cart' }, { status: 500 })
      }

      return NextResponse.json({ success: true, message: 'Cart updated' }, { status: 200 })
    }

    if (product.stock > 0 && quantity > product.stock) {
      return NextResponse.json({ error: 'Not enough stock available' }, { status: 400 })
    }

    const { error: insertError } = await supabase
      .from('user_cart')
      .insert({
        user_id: userId,
        product_id: productId,
        quantity,
      })

    if (insertError) {
      console.error('Cart insert error:', insertError)
      return NextResponse.json({ error: 'Failed to add to cart' }, { status: 500 })
    }

    return NextResponse.json({ success: true, message: 'Added to cart' }, { status: 201 })
  } catch (error) {
    console.error('Cart add error:', error)
    return NextResponse.json({ error: 'Internal server error' }, { status: 500 })
  }
}

