          >
            <a
              href={ctaLink}
              className="inline-flex items-center gap-2 text-[11px] uppercase tracking-[0.2em] text-white/70 hover:text-[#C9A96E] transition-colors border-b border-white/20 pb-1 hover:border-[#C9A96E]"
