'use client'

import { useRef, useEffect, useState, useCallback, useMemo } from 'react'
import Image from 'next/image'
import { cn } from '@/lib/utils'
import { useIntersectionObserver } from '@/hooks/useIntersectionObserver'

// Seeded pseudo-random for deterministic scatter
function seededRandom(seed: number) {
    const x = Math.sin(seed) * 10000
    return x - Math.floor(x)
}

interface LookbookProps {
    images?: { id: string; image_url: string; title?: string; subtitle?: string; link?: string }[]
    title?: string
    subtitle?: string
}

// Generate column-based positions for images (4 columns)
function generateGridPositions(count: number) {
    const positions: { top: string; left: string; width: string; speed: number; zIndex: number; opacity: number; blur: string }[] = []

    // Config for each column to create varied movement and explicit sizes
    const columns = [
        { left: '2%', width: '18vw', speed: 0.7, zIndex: 1 },   // Medium-Small
        { left: '22%', width: '30vw', speed: 1.3, zIndex: 3 },  // Big
        { left: '55%', width: '24vw', speed: 0.9, zIndex: 2 },  // Medium
        { left: '82%', width: '15vw', speed: 0.5, zIndex: 0 },  // Smallest
    ]

    for (let i = 0; i < count; i++) {
        const colIndex = i % 4
        const col = columns[colIndex]

        // Distribute images vertically with significant spacing and high randomness
        const row = Math.floor(i / 4)
        const topOffset = 3 + (row * 24) + (seededRandom(i) * 15)

        positions.push({
            top: `${topOffset}%`,
            left: col.left,
            width: col.width,
            speed: col.speed,
            zIndex: col.zIndex,
            opacity: col.zIndex === 0 ? 0.8 : 1,
            blur: col.zIndex === 0 ? '1px' : '0px',
        })
    }
    return positions
}

export default function Lookbook({ images = [], title = "THE LOOK", subtitle = "Discover" }: LookbookProps) {
    // Only use provided props if they exist, otherwise fallback
    const displayTitle = title || "THE LOOK"
    const displaySubtitle = subtitle || "Discover"

    const containerRef = useRef<HTMLDivElement>(null)
    const { ref: sectionRef, isIntersecting } = useIntersectionObserver({ threshold: 0.1 })
    const imageElementsRef = useRef<(HTMLDivElement | null)[]>([])
    const rafRef = useRef<number>(0)
    const [isMobile, setIsMobile] = useState(false)

    // Detect mobile for responsive scatter widths
    useEffect(() => {
        const mq = window.matchMedia('(max-width: 768px)')
        setIsMobile(mq.matches)
        const handler = (e: MediaQueryListEvent) => setIsMobile(e.matches)
        mq.addEventListener('change', handler)
        return () => mq.removeEventListener('change', handler)
    }, [])

    // Memoize positions for the new grid layout
    const positions = useMemo(() => generateGridPositions(images.length), [images.length])

    // Use rAF-based parallax that writes directly to DOM — zero re-renders
    useEffect(() => {
        if (!images || images.length === 0) return

        const onScroll = () => {
            cancelAnimationFrame(rafRef.current)
            rafRef.current = requestAnimationFrame(() => {
                const container = containerRef.current
                if (!container) return

                const rect = container.getBoundingClientRect()
                if (rect.top >= window.innerHeight || rect.bottom <= 0) return

                const totalScrollable = rect.height + window.innerHeight
                const scrolled = window.innerHeight - rect.top
                const progress = Math.max(0, Math.min(1, scrolled / totalScrollable))
                const scrollVal = progress * 1000

                // Write transforms directly to each image element — no state updates
                // We add an extra offset to columns to make them feel "untethered"
                imageElementsRef.current.forEach((el, i) => {
                    if (!el) return
                    const pos = positions[i]
                    if (!pos) return
                    el.style.transform = `translateY(${-scrollVal * pos.speed}px)`
                })
            })
        }

        window.addEventListener('scroll', onScroll, { passive: true })
        onScroll() // initial calc

        return () => {
            window.removeEventListener('scroll', onScroll)
            cancelAnimationFrame(rafRef.current)
        }
    }, [images, positions])

    if (!images || images.length === 0) {
        return null
    }

    return (
        <section
            ref={(node) => {
                (sectionRef as React.MutableRefObject<HTMLElement | null>).current = node;
                (containerRef as React.MutableRefObject<HTMLElement | null>).current = node;
            }}
            className="relative w-full h-[450vh] md:h-[500vh] bg-[#FAF9F6]"
            aria-label={`${subtitle} — ${title}`}
        >
            {/* Sticky Text Container */}
            <div className="sticky top-0 h-screen w-full flex flex-col items-center justify-center pointer-events-none z-20">
                <div
                    className={cn(
                        "text-center transition-all duration-1000 transform",
                        isIntersecting ? "opacity-100 scale-100" : "opacity-0 scale-95"
                    )}
                >
                    <span className="text-[12px] md:text-[14px] uppercase tracking-[0.4em] text-[#1A1A1A] font-medium mb-4 md:mb-6 block drop-shadow-sm">
                        {displaySubtitle}
                    </span>
                    <h2 className="text-6xl md:text-8xl lg:text-9xl font-serif text-[#1A1A1A] tracking-widest drop-shadow-md">
                        {displayTitle}
                    </h2>
                </div>
            </div>

            {/* Structured Column Container */}
            <div className="absolute top-0 left-0 w-full h-full pointer-events-none z-0 overflow-hidden">
                {images.map((img, index) => {
                    const pos = positions[index]
                    if (!pos) return null

                    // Mobile adjustment: distribute into 2 columns instead of 4
                    const isEven = index % 2 === 0
                    const row = Math.floor(index / 2)
                    // Mix sizes on mobile
                    const mobileWidth = isEven ? (row % 2 === 0 ? '55vw' : '40vw') : (row % 2 === 0 ? '38vw' : '50vw')
                    const mobileLeft = isEven ? '3%' : (row % 2 === 0 ? '58%' : '47%')

                    const mobileAdjustedPos = isMobile ? {
                        ...pos,
                        left: mobileLeft,
                        top: `${4 + (row * 18) + (seededRandom(index) * 12)}%`,
                        width: mobileWidth
                    } : pos

                    const imageContent = (
                        <>
                            <Image
                                src={img.image_url}
                                alt={img.title || `Lookbook image ${index + 1}`}
                                fill
                                className="object-cover transition-transform duration-700 group-hover:scale-105"
                                sizes={isMobile ? '45vw' : '25vw'}
                                loading={index < 6 ? 'eager' : 'lazy'}
                            />
                            {img.title && (
                                <div className="absolute inset-0 flex flex-col items-center justify-center bg-black/40 opacity-100 lg:opacity-0 lg:group-hover:opacity-100 transition-opacity duration-300">
                                    <h3 className="text-white font-serif text-lg md:text-xl mb-1 text-center px-4">{img.title}</h3>
                                    {img.subtitle && <p className="text-white/80 text-[10px] md:text-sm uppercase tracking-widest text-center px-4">{img.subtitle}</p>}
                                </div>
                            )}
                        </>
                    )

                    return (
                        <div
                            key={img.id || index}
                            ref={(el) => { imageElementsRef.current[index] = el }}
                            className="absolute shadow-xl will-change-transform"
                            style={{
                                top: mobileAdjustedPos.top,
                                left: mobileAdjustedPos.left,
                                width: mobileAdjustedPos.width,
                                zIndex: mobileAdjustedPos.zIndex,
                                opacity: mobileAdjustedPos.opacity,
                                filter: `blur(${mobileAdjustedPos.blur})`,
                            }}
                        >
                            <div className="relative w-full pt-[125%] overflow-hidden bg-[#E8E4DF] group pointer-events-auto cursor-pointer rounded-sm">
                                {img.link ? (
                                    <a href={img.link} className="absolute inset-0 z-10 block" aria-label={img.title || `View lookbook item ${index + 1}`}>
                                        {imageContent}
                                    </a>
                                ) : (
                                    imageContent
                                )}
                            </div>
                        </div>
                    )
                })}
            </div>
        </section>
    )
}

import { useState, useEffect } from 'react'
import { cn } from '@/lib/utils'
import { useIntersectionObserver } from '@/hooks/useIntersectionObserver'
import { ProductReview, ProductReviewStats } from '@/lib/supabase'

interface ProductReviewsProps {
  productId: string
  initialReviews?: ProductReview[]
  initialStats?: ProductReviewStats | null
}

const StarIcon = ({ filled, size = 20 }: { filled: boolean; size?: number }) => (
  <svg
    width={size}
    height={size}
    viewBox="0 0 24 24"
    fill={filled ? 'currentColor' : 'none'}
    stroke="currentColor"
    strokeWidth="1.5"
  >
    <path d="M12 2l3.09 6.26L22 9.27l-5 4.87 1.18 6.88L12 17.77l-6.18 3.25L7 14.14 2 9.27l6.91-1.01L12 2z" />
  </svg>
)

export default function ProductReviews({ productId, initialReviews, initialStats }: ProductReviewsProps) {
  const hasInitialData = initialReviews !== undefined
  const [reviews, setReviews] = useState<ProductReview[]>(initialReviews || [])
  const [stats, setStats] = useState<ProductReviewStats | null>(initialStats ?? null)
  const [loading, setLoading] = useState(!hasInitialData)
  const [showAll, setShowAll] = useState(false)

  // Hook must be called before any conditional returns (Rules of Hooks)
  const { ref: sectionRef, isIntersecting } = useIntersectionObserver({ threshold: 0.1 })

  // Only fetch from API if no initial data was provided (saves serverless invocations)
  useEffect(() => {
    if (hasInitialData) return
    if (productId) {
      fetchReviews()
    }
  }, [productId, hasInitialData])

  const fetchReviews = async () => {
    try {
      const response = await fetch(`/api/reviews?product_id=${productId}&limit=20`)
      if (response.ok) {
        const data = await response.json()
        setReviews(data.reviews || [])
        setStats(data.stats || null)
      }
    } catch (error) {
      console.error('Failed to fetch reviews:', error)
    } finally {
      setLoading(false)
    }
  }

  const formatDate = (dateStr: string) => {
    return new Date(dateStr).toLocaleDateString('en-US', {
      month: 'long',
      day: 'numeric',
      year: 'numeric'
    })
  }

  const renderStars = (rating: number, size = 16) => {
    return (
      <div className="flex items-center gap-0.5">
        {[1, 2, 3, 4, 5].map(star => (
          <span
            key={star}
            className={star <= rating ? 'text-[#FDB022]' : 'text-[#E5E7EB]'}
          >
            <StarIcon filled={star <= rating} size={size} />
          </span>
        ))}
      </div>
    )
  }

  const getRatingPercentage = (count: number) => {
    if (!stats || stats.review_count === 0) return 0
    return Math.round((count / stats.review_count) * 100)
  }

  if (loading) {
    return (
      <div className="py-12 text-center">
        <div className="inline-block animate-spin rounded-full h-8 w-8 border-2 border-[#FDB022] border-t-transparent"></div>
      </div>
    )
  }

  if (reviews.length === 0) {
    return (
      <div
        className="border-t border-[#E5E7EB] mt-16 pt-12"
      >
        <h2 className="text-2xl md:text-3xl font-medium font-display text-[#1A1A1A] mb-6">Customer Reviews</h2>
        <div className="text-center py-12 bg-[#F8F7F5] rounded-lg font-poppins">
          <div className="text-[#1A1A1A] mb-2 font-semibold">No reviews yet</div>
          <p className="text-sm text-[#4B5563] font-normal">
            Be the first to review this product after your purchase
          </p>
        </div>
      </div>
    )
  }

  const displayedReviews = showAll ? reviews : reviews.slice(0, 3)

  return (
    <div
      ref={sectionRef}
      className={cn(
        "border-t border-[#E5E7EB] mt-16 pt-12 invisible-before-reveal",
        isIntersecting && "reveal-slide-up"
      )}
    >
      <h2 className="text-2xl md:text-3xl font-medium font-display text-[#1A1A1A] mb-8">Customer Reviews</h2>

      {/* Stats Summary */}
      {stats && stats.review_count > 0 && (
        <div className="flex flex-col md:flex-row gap-8 mb-10 pb-10 border-b border-[#E5E7EB] font-poppins">
          {/* Average Rating */}
          <div className="text-center md:text-left md:pr-8 md:border-r md:border-[#E5E7EB]">
            <div className="text-5xl font-medium text-[#1A1A1A] mb-2">
              {stats.average_rating}
            </div>
            <div className="mb-2">{renderStars(Math.round(stats.average_rating), 20)}</div>
            <div className="text-sm text-[#4B5563] font-normal">
              Based on {stats.review_count} review{stats.review_count !== 1 ? 's' : ''}
            </div>
          </div>

          {/* Rating Distribution */}
          <div className="flex-1 space-y-2">
            {[5, 4, 3, 2, 1].map(rating => {
              const count = stats[`${['one', 'two', 'three', 'four', 'five'][rating - 1]}_star` as keyof ProductReviewStats] as number
              const percentage = getRatingPercentage(count)
              return (
                <div key={rating} className="flex items-center gap-3">
                  <span className="text-sm text-[#4B5563] w-12 font-normal">{rating} star</span>
                  <div className="flex-1 h-2 bg-[#E5E7EB] rounded-full overflow-hidden">
                    <div
                      className="h-full bg-[#FDB022] rounded-full transition-all duration-500"
                      style={{ width: `${percentage}%` }}
                    />
                  </div>
                  <span className="text-sm text-[#4B5563] w-10 text-right font-normal">{count}</span>
                </div>
              )
            })}
          </div>
        </div>
      )}

      {/* Reviews List */}
      <div className="space-y-6 font-poppins">
        {displayedReviews.map((review, index) => (
          <div
            key={review.id}
            className={cn(
              "pb-6 border-b border-[#F3F4F6] last:border-0 invisible-before-reveal",
              isIntersecting && "reveal-slide-up"
            )}
            style={{ animationDelay: isIntersecting ? `${index * 100 + 200}ms` : '0ms' }}
          >
            <div className="flex items-start justify-between mb-3">
              <div>
                <div className="flex items-center gap-3 mb-1">
                  {renderStars(review.rating)}
                  {review.is_verified_purchase && (
                    <span className="text-[10px] uppercase tracking-wider px-2 py-0.5 bg-[#FDB022]/10 text-[#FDB022] rounded-full font-bold">
                      Verified Purchase
                    </span>
                  )}
                </div>
                {review.title && (
                  <h4 className="font-bold text-[#1A1A1A]">{review.title}</h4>
                )}
              </div>
              <span className="text-xs text-[#6B7280] font-normal">
                {formatDate(review.created_at)}
              </span>
            </div>
            <p className="text-[#374151] text-base leading-relaxed mb-2 font-normal">
              {review.comment}
            </p>
            <p className="text-xs text-[#1A1A1A] font-semibold">
              — {review.user_name}
            </p>
          </div>
        ))}
      </div>

      {/* Show More Button */}
      {reviews.length > 3 && (
        <div className="text-center mt-8">
          <button
            onClick={() => setShowAll(!showAll)}
            className="px-8 py-3 border border-[#E8E4DF] text-[#1A1A1A] hover:border-[#1A1A1A] hover:text-[#888] transition-all duration-300 text-[11px] uppercase tracking-[0.2em] font-medium"
          >
            {showAll ? 'Show Less' : `Show All ${reviews.length} Reviews`}
          </button>
        </div>
      )}
    </div>
  )
}

