import { cn } from '@/lib/utils'

import { useEffect, useState } from 'react'

interface ToastProps {
  message: string
  type?: 'success' | 'error' | 'info'
  isVisible: boolean
  onClose: () => void
  duration?: number
}

export default function Toast({ message, type = 'success', isVisible, onClose, duration = 5000 }: ToastProps) {
  const [render, setRender] = useState(isVisible)

  // eslint-disable-next-line react-hooks/set-state-in-effect
  useEffect(() => {
    if (isVisible) setRender(true)
  }, [isVisible])

  useEffect(() => {
    if (isVisible && duration > 0) {
      const timer = setTimeout(() => {
        onClose()
      }, duration)
      return () => clearTimeout(timer)
    }
  }, [isVisible, onClose, duration])

  const getIcon = () => {
    switch (type) {
      case 'success':
        return (
          <svg className="w-5 h-5 text-green-600" fill="currentColor" viewBox="0 0 20 20">
            <path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zm3.707-9.293a1 1 0 00-1.414-1.414L9 10.586 7.707 9.293a1 1 0 00-1.414 1.414l2 2a1 1 0 001.414 0l4-4z" clipRule="evenodd" />
          </svg>
        )
      case 'error':
        return (
          <svg className="w-5 h-5 text-red-600" fill="currentColor" viewBox="0 0 20 20">
            <path fillRule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zm-7 4a1 1 0 11-2 0 1 1 0 012 0zm-1-9a1 1 0 00-1 1v4a1 1 0 102 0V6a1 1 0 00-1-1z" clipRule="evenodd" />
          </svg>
        )
      default:
        return (
          <svg className="w-5 h-5 text-blue-600" fill="currentColor" viewBox="0 0 20 20">
            <path fillRule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zm-7-4a1 1 0 11-2 0 1 1 0 012 0zM9 9a1 1 0 000 2v3a1 1 0 001 1h1a1 1 0 100-2v-3a1 1 0 00-1-1H9z" clipRule="evenodd" />
          </svg>
        )
    }
  }

  const getBgColor = () => {
    switch (type) {
      case 'success':
        return 'bg-green-50 border-green-200'
      case 'error':
        return 'bg-red-50 border-red-200'
      default:
        return 'bg-blue-50 border-blue-200'
    }
  }

  if (!render) return null

  return (
    <div
      className={cn(
        `fixed top-6 right-6 z-[10000] max-w-sm w-full ${getBgColor()} border rounded-lg shadow-lg p-4 transition-all duration-300 transform`,
        isVisible ? "translate-y-0 opacity-100 scale-100" : "-translate-y-4 opacity-0 scale-95"
      )}
      onTransitionEnd={() => {
        if (!isVisible) setRender(false)
      }}
    >
      <div className="flex items-start">
        <div className="flex-shrink-0">
          {getIcon()}
        </div>
        <div className="ml-3 flex-1">
          <p className="text-sm font-medium text-gray-900">{message}</p>
        </div>
        <div className="ml-4 flex-shrink-0">
          <button
            onClick={onClose}
            className="inline-flex text-gray-600 hover:text-gray-600 focus:outline-none"
          >
            <svg className="w-4 h-4" fill="currentColor" viewBox="0 0 20 20">
              <path fillRule="evenodd" d="M4.293 4.293a1 1 0 011.414 0L10 8.586l4.293-4.293a1 1 0 111.414 1.414L11.414 10l4.293 4.293a1 1 0 01-1.414 1.414L10 11.414l-4.293 4.293a1 1 0 01-1.414-1.414L8.586 10 4.293 5.707a1 1 0 010-1.414z" clipRule="evenodd" />
            </svg>
          </button>
        </div>
      </div>
    </div>
  )
}

import { useState, useRef, useCallback } from 'react'
import { useAdminAuth } from '@/context/AdminAuthContext'
import Image from 'next/image'

interface AdminImageUploadProps {
  /** Current image URL value */
  value: string
  /** Called when the URL changes (either by upload or manual paste) */
  onChange: (url: string) => void
  /** Label for the field */
  label?: string
  /** Storage folder: hero, collections, or products (default) */
  folder?: 'hero' | 'collections' | 'products'
  /** Placeholder for the URL input */
  placeholder?: string
}

const ALLOWED_TYPES = ['image/jpeg', 'image/jpg', 'image/png', 'image/webp', 'image/avif']
const MAX_FILE_SIZE = 8 * 1024 * 1024 // 8 MB

export default function AdminImageUpload({
  value,
  onChange,
  label = 'Image',
  folder = 'products',
  placeholder = 'Or paste image URL...'
}: AdminImageUploadProps) {
  const { token } = useAdminAuth()
  const [preview, setPreview] = useState(value || '')
  const [uploading, setUploading] = useState(false)
  const [progress, setProgress] = useState(0)
  const [error, setError] = useState('')
  const [dragOver, setDragOver] = useState(false)
  const fileInputRef = useRef<HTMLInputElement>(null)

  const uploadFile = useCallback(async (file: File) => {
    // Validate
    if (!ALLOWED_TYPES.includes(file.type)) {
      setError('Unsupported format. Use JPEG, PNG, WebP, or AVIF.')
      return
    }
    if (file.size > MAX_FILE_SIZE) {
      setError(`File too large (${(file.size / (1024 * 1024)).toFixed(1)} MB). Max 8 MB.`)
      return
    }

    setError('')
    setUploading(true)
    setProgress(0)

    // Show local preview immediately
    const localPreview = URL.createObjectURL(file)
    setPreview(localPreview)

    try {
      // 1. Get signed upload URL
      const res = await fetch('/api/admin/upload-url', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          ...(token ? { Authorization: `Bearer ${token}` } : {})
        },
        body: JSON.stringify({ filename: file.name, contentType: file.type, folder })
      })

      if (!res.ok) {
        const body = await res.json().catch(() => ({}))
        throw new Error(body.error || 'Failed to get upload URL')
      }

      const { signedUrl, publicUrl } = await res.json()

      // 2. Upload via XHR for progress tracking
      await new Promise<void>((resolve, reject) => {
        const xhr = new XMLHttpRequest()

        xhr.upload.addEventListener('progress', (e) => {
          if (e.lengthComputable) {
            setProgress(Math.round((e.loaded / e.total) * 100))
          }
        })

        xhr.addEventListener('load', () => {
          if (xhr.status >= 200 && xhr.status < 300) {
            resolve()
          } else {
            reject(new Error(`Upload failed (${xhr.status})`))
          }
        })

        xhr.addEventListener('error', () => reject(new Error('Network error')))
        xhr.addEventListener('abort', () => reject(new Error('Upload cancelled')))

        xhr.open('PUT', signedUrl)
        xhr.setRequestHeader('Content-Type', file.type)
        xhr.send(file)
      })

      // 3. Success
      setPreview(publicUrl)
      onChange(publicUrl)
      setProgress(100)
    } catch (err: any) {
      setError(err.message || 'Upload failed')
      setPreview(value) // restore previous
    } finally {
      setUploading(false)
      URL.revokeObjectURL(localPreview)
    }
  }, [token, folder, onChange, value])

  const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0]
    if (file) uploadFile(file)
    // Reset so same file can be re-selected
    if (fileInputRef.current) fileInputRef.current.value = ''
  }

  const handleDrop = useCallback((e: React.DragEvent) => {
    e.preventDefault()
    setDragOver(false)
    const file = e.dataTransfer.files?.[0]
    if (file) uploadFile(file)
  }, [uploadFile])

  const handleUrlChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const url = e.target.value
    onChange(url)
    setPreview(url)
    setError('')
  }

  return (
    <div>
      <label className="block text-[#a1a1a1] text-[13px] font-medium mb-2">{label}</label>

      {/* Preview */}
      {preview && (
        <div className="mb-3 relative w-full h-40 sm:h-48 rounded-lg overflow-hidden bg-[#1a1a1a] border border-[#1a1a1a]">
          <Image src={preview} alt="Preview" fill className="object-cover" unoptimized />
          <button
            type="button"
            onClick={() => { onChange(''); setPreview(''); }}
            className="absolute top-2 right-2 w-8 h-8 flex items-center justify-center bg-[#ff4444]/90 hover:bg-[#ff4444] rounded-full text-white transition-colors text-sm shadow-lg active:scale-90"
            title="Remove image"
            aria-label="Remove image"
          >
            ✕
          </button>
        </div>
      )}

      {/* Upload zone */}
      <div
        onDragOver={(e) => { e.preventDefault(); setDragOver(true) }}
        onDragLeave={() => setDragOver(false)}
        onDrop={handleDrop}
        className={`relative border border-dashed rounded-lg transition-colors ${
          dragOver
            ? 'border-white/50 bg-white/5'
            : 'border-[#333] hover:border-[#555]'
        }`}
      >
        <label className="flex items-center justify-center gap-2 cursor-pointer py-4 sm:py-3 px-4">
          <input
            ref={fileInputRef}
            type="file"
            accept="image/*"
            onChange={handleFileSelect}
            className="hidden"
            disabled={uploading}
          />
          <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" className="text-[#888]">
            <path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4" />
            <polyline points="17 8 12 3 7 8" />
            <line x1="12" y1="3" x2="12" y2="15" />
          </svg>
          <span className="text-[#888] text-sm">
            {uploading ? 'Uploading...' : 'Choose file or drag & drop'}
          </span>
        </label>

        {/* Progress bar */}
        {uploading && (
          <div className="absolute bottom-0 left-0 right-0 h-1 bg-[#1a1a1a] rounded-b-lg overflow-hidden">
            <div
              className="h-full bg-[#C9A96E] transition-all duration-300 ease-out"
              style={{ width: `${progress}%` }}
            />
          </div>
        )}
      </div>

      {/* URL fallback */}
      <input
        type="url"
        value={value}
        onChange={handleUrlChange}
        className="admin-input w-full mt-2"
        placeholder={placeholder}
        disabled={uploading}
      />

      {/* Error */}
      {error && (
        <p className="text-[#ff6166] text-[11px] mt-1">{error}</p>
      )}
    </div>
  )
}

'use client'

import { useEffect, useState } from 'react'
import { useRouter } from 'next/navigation'
import { Command } from 'cmdk'
import { supabase } from '@/lib/supabase'

export function CommandPalette() {
    const [open, setOpen] = useState(false)
    const [search, setSearch] = useState('')
    const [products, setProducts] = useState<any[]>([])
    const [orders, setOrders] = useState<any[]>([])
    const [loading, setLoading] = useState(false)
    const router = useRouter()

    // Toggle the menu when ⌘K is pressed
    useEffect(() => {
        const down = (e: KeyboardEvent) => {
            if (e.key === 'k' && (e.metaKey || e.ctrlKey)) {
                e.preventDefault()
                setOpen((open) => !open)
            }
        }

        document.addEventListener('keydown', down)
        return () => document.removeEventListener('keydown', down)
    }, [])

    // Fetch data on search
    // eslint-disable-next-line react-hooks/set-state-in-effect
    useEffect(() => {
        if (!search || search.length < 2) {
            setProducts([])
            setOrders([])
            return
        }

        const fetchResults = async () => {
            setLoading(true)

            // Sanitize search input — escape PostgREST special characters
            const sanitized = search.replace(/[%_\\(),.]/g, c => `\\${c}`)

            const { data: pData } = await supabase
                .from('products')
                .select('id, name')
                .ilike('name', `%${sanitized}%`)
                .limit(5)

            // For orders, only use ilike on user_name (avoid injecting into .or filters)
            const { data: oData } = await supabase
                .from('orders')
                .select('id, user_name')
                .ilike('user_name', `%${sanitized}%`)
                .limit(5)

            setProducts(pData || [])
            setOrders(oData || [])
            setLoading(false)
        }

        const timeout = setTimeout(fetchResults, 300)
        return () => clearTimeout(timeout)
    }, [search])

    const runCommand = (command: () => void) => {
        setOpen(false)
        command()
    }

    const navigate = (href: string) => {
        router.push(href)
    }

    // Workaround for hydration errors with Command.Dialog in some Next.js setups
    const [mounted, setMounted] = useState(false)
    // eslint-disable-next-line react-hooks/set-state-in-effect
    useEffect(() => setMounted(true), [])
    if (!mounted) return null

    return (
        <Command.Dialog
            open={open}
            onOpenChange={setOpen}
            label="Global Command Menu"
            // Style using Tailwind directly to override cmdk defaults if needed
            className="fixed inset-0 z-[100] bg-black/60 backdrop-blur-sm flex items-start justify-center pt-[15vh] px-4"
        >
            <div
                // cmdk injects styles but we override them with tailwind
                className="w-full max-w-xl bg-[#1A1A1A] border border-[#333] rounded-xl shadow-2xl overflow-hidden flex flex-col"
                style={{ height: 'auto', maxHeight: '60vh' }}
            >
                <div className="flex items-center px-4 border-b border-[#333]">
                    <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="#666" strokeWidth="2">
                        <circle cx="11" cy="11" r="8"></circle><line x1="21" y1="21" x2="16.65" y2="16.65"></line>
                    </svg>
                    <Command.Input
                        value={search}
                        onValueChange={setSearch}
                        placeholder="Search products, orders, or pages..."
                        className="w-full bg-transparent px-3 py-4 text-white text-base outline-none placeholder:text-[#666]"
                        style={{ border: 'none', boxShadow: 'none' }}
                    />
                </div>

                <Command.List className="overflow-y-auto p-2 scrollbar-thin scrollbar-thumb-[#333] scrollbar-track-transparent">
                    {loading && <Command.Loading className="p-4 text-sm text-[#666] text-center">Searching database...</Command.Loading>}

                    <Command.Empty className="p-6 text-sm text-[#666] text-center">No results found for &quot;{search}&quot;</Command.Empty>

                    <Command.Group heading="Pages" className="px-2 py-2 text-xs font-semibold text-[#888] mb-2 [&_[cmdk-item]]:mt-1 [&_[cmdk-group-heading]]:mb-2 [&_[cmdk-group-heading]]:px-2">
                        <Command.Item onSelect={() => runCommand(() => navigate('/admin/dashboard'))} className="px-3 py-2 text-sm text-white hover:bg-[#262626] aria-selected:bg-[#262626] rounded cursor-pointer outline-none transition-colors">
                            Dashboard Overview
                        </Command.Item>
                        <Command.Item onSelect={() => runCommand(() => navigate('/admin/products'))} className="px-3 py-2 text-sm text-white hover:bg-[#262626] aria-selected:bg-[#262626] rounded cursor-pointer outline-none transition-colors">
                            Manage Products
                        </Command.Item>
                        <Command.Item onSelect={() => runCommand(() => navigate('/admin/orders'))} className="px-3 py-2 text-sm text-white hover:bg-[#262626] aria-selected:bg-[#262626] rounded cursor-pointer outline-none transition-colors">
                            View Orders
                        </Command.Item>
                        <Command.Item onSelect={() => runCommand(() => navigate('/admin/builder'))} className="px-3 py-2 text-sm text-white hover:bg-[#262626] aria-selected:bg-[#262626] rounded cursor-pointer outline-none transition-colors">
                            Visual Layout Builder
                        </Command.Item>
                    </Command.Group>

                    {products.length > 0 && (
                        <Command.Group heading="Products" className="px-2 py-2 border-t border-[#333] text-xs font-semibold text-[#888] mb-2 [&_[cmdk-item]]:mt-1 [&_[cmdk-group-heading]]:mb-2 [&_[cmdk-group-heading]]:px-2">
                            {products.map(p => (
                                <Command.Item
                                    key={p.id}
                                    onSelect={() => runCommand(() => navigate(`/admin/products?edit=${p.id}`))}
                                    className="px-3 py-2 text-sm text-white hover:bg-[#262626] aria-selected:bg-[#262626] rounded cursor-pointer flex justify-between items-center outline-none transition-colors"
                                >
                                    <span>{p.name}</span>
                                    <span className="text-xs text-[#666] border border-[#333] px-1.5 py-0.5 rounded">Edit</span>
                                </Command.Item>
                            ))}
                        </Command.Group>
                    )}

                    {orders.length > 0 && (
                        <Command.Group heading="Orders" className="px-2 py-2 border-t border-[#333] text-xs font-semibold text-[#888] mb-2 [&_[cmdk-item]]:mt-1 [&_[cmdk-group-heading]]:mb-2 [&_[cmdk-group-heading]]:px-2">
                            {orders.map(o => (
                                <Command.Item
                                    key={o.id}
                                    onSelect={() => runCommand(() => navigate(`/admin/orders?id=${o.id}`))}
                                    className="px-3 py-2 text-sm text-[#ddd] hover:bg-[#262626] aria-selected:bg-[#262626] rounded cursor-pointer flex justify-between items-center outline-none transition-colors"
                                >
                                    <span>Order {o.id.split('-')[0]} • <span className="text-white">{o.user_name}</span></span>
                                    <span className="text-xs text-[#666] border border-[#333] px-1.5 py-0.5 rounded">View</span>
                                </Command.Item>
                            ))}
                        </Command.Group>
                    )}
                </Command.List>
                <div className="border-t border-[#333] p-3 flex items-center justify-between text-xs text-[#666]">
                    <span>Search powered by Supabase</span>
                    <div className="flex gap-2 items-center">
                        <span>Use</span>
                        <kbd className="px-1.5 py-0.5 bg-[#262626] text-[#888] rounded border border-[#444] font-sans">↑</kbd>
                        <kbd className="px-1.5 py-0.5 bg-[#262626] text-[#888] rounded border border-[#444] font-sans">↓</kbd>
                        <span>to navigate</span>
                        <kbd className="px-1.5 py-0.5 bg-[#262626] text-[#888] rounded border border-[#444] font-sans ml-2">↵</kbd>
                        <span>to select</span>
                    </div>
                </div>
            </div>
        </Command.Dialog>
    )
}

import { useState, useCallback } from 'react'
import Image from 'next/image'
import {
  DndContext,
  closestCenter,
  KeyboardSensor,
  PointerSensor,
  TouchSensor,
  useSensor,
  useSensors,
  DragEndEvent,
  DragStartEvent,
  DragOverlay,
} from '@dnd-kit/core'
import {
  arrayMove,
  SortableContext,
  sortableKeyboardCoordinates,
  rectSortingStrategy,
  useSortable,
} from '@dnd-kit/sortable'
import { CSS } from '@dnd-kit/utilities'

interface SortableImageGridProps {
  images: string[]
  onReorder: (images: string[]) => void
  onRemove: (index: number) => void
  maxImages?: number
}

// Individual sortable image item
function SortableImageItem({
  url,
  index,
  isMain,
  onRemove,
  totalImages,
}: {
  url: string
  index: number
  isMain: boolean
  onRemove: () => void
  totalImages: number
}) {
  const {
    attributes,
    listeners,
    setNodeRef,
    transform,
    transition,
    isDragging,
  } = useSortable({ id: url + '__' + index })

  const style = {
    transform: CSS.Transform.toString(transform),
    transition,
    zIndex: isDragging ? 50 : 'auto',
    opacity: isDragging ? 0.4 : 1,
  }

  return (
    <div
      ref={setNodeRef}
      style={style as any}
      className={`relative aspect-square rounded-xl overflow-hidden bg-[#111] border-2 group transition-all duration-200
        ${isDragging
          ? 'border-[#0070f3] ring-2 ring-[#0070f3]/30 scale-105 shadow-2xl'
          : 'border-[#222] hover:border-[#444]'
        }
      `}
    >
      <Image src={url} alt={`Image ${index + 1}`} fill className="object-cover" />

      {/* Drag handle overlay — visible on hover/touch */}
      <div
        {...attributes}
        {...listeners}
        className="absolute inset-0 cursor-grab active:cursor-grabbing touch-manipulation"
        aria-label={`Drag to reorder image ${index + 1}`}
      >
        {/* Grip indicator — always visible on mobile, hover on desktop */}
        <div className="absolute top-2 left-2 w-7 h-7 rounded-lg bg-black/60 backdrop-blur-sm flex items-center justify-center opacity-100 sm:opacity-0 sm:group-hover:opacity-100 transition-opacity text-white/80">
          <svg width="14" height="14" viewBox="0 0 24 24" fill="currentColor">
            <circle cx="8" cy="4" r="2" /><circle cx="16" cy="4" r="2" />
            <circle cx="8" cy="12" r="2" /><circle cx="16" cy="12" r="2" />
            <circle cx="8" cy="20" r="2" /><circle cx="16" cy="20" r="2" />
          </svg>
        </div>
      </div>

      {/* Remove button — always visible on mobile, hover on desktop */}
      <button
        type="button"
        onClick={(e) => { e.stopPropagation(); onRemove() }}
        className="absolute top-2 right-2 w-7 h-7 rounded-lg bg-[#ff4444]/90 hover:bg-[#ff4444] flex items-center justify-center opacity-100 sm:opacity-0 sm:group-hover:opacity-100 transition-all text-white shadow-lg active:scale-90"
        title="Remove image"
      >
        <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round">
          <line x1="18" y1="6" x2="6" y2="18" />
          <line x1="6" y1="6" x2="18" y2="18" />
        </svg>
      </button>

      {/* Main badge */}
      {isMain && (
        <span className="absolute bottom-2 left-2 bg-white text-black text-[10px] px-2 py-1 rounded-md font-bold tracking-wide shadow-lg uppercase">
          Main
        </span>
      )}

      {/* Position number */}
      {!isMain && (
        <span className="absolute bottom-2 left-2 bg-black/70 backdrop-blur-sm text-white/90 text-[10px] px-2 py-1 rounded-md font-medium">
          {index + 1}
        </span>
      )}
    </div>
  )
}

export default function SortableImageGrid({
  images,
  onReorder,
  onRemove,
  maxImages = 10,
}: SortableImageGridProps) {
  const [activeId, setActiveId] = useState<string | null>(null)
  const [activeIndex, setActiveIndex] = useState<number | null>(null)

  // Configure sensors for both mouse and touch
  const sensors = useSensors(
    useSensor(PointerSensor, {
      activationConstraint: { distance: 5 },
    }),
    useSensor(TouchSensor, {
      activationConstraint: { delay: 200, tolerance: 8 },
    }),
    useSensor(KeyboardSensor, {
      coordinateGetter: sortableKeyboardCoordinates,
    })
  )

  const items = images.map((url, i) => url + '__' + i)

  const handleDragStart = useCallback((event: DragStartEvent) => {
    const id = event.active.id as string
    setActiveId(id)
    const idx = items.indexOf(id)
    setActiveIndex(idx)
  }, [items])

  const handleDragEnd = useCallback((event: DragEndEvent) => {
    const { active, over } = event
    setActiveId(null)
    setActiveIndex(null)

    if (over && active.id !== over.id) {
      const oldIndex = items.indexOf(active.id as string)
      const newIndex = items.indexOf(over.id as string)
      const newImages = arrayMove(images, oldIndex, newIndex)
      onReorder(newImages)
    }
  }, [items, images, onReorder])

  if (images.length === 0) return null

  return (
    <div>
      <div className="flex items-center gap-3 mb-3">
        <p className="text-[11px] uppercase tracking-wider text-[#555] font-medium">
          Drag to reorder
        </p>
        <span className="text-[11px] text-[#333]">•</span>
        <p className="text-[11px] text-[#555]">
          First image = main product photo
        </p>
      </div>

      <DndContext
        sensors={sensors}
        collisionDetection={closestCenter}
        onDragStart={handleDragStart}
        onDragEnd={handleDragEnd}
      >
        <SortableContext items={items} strategy={rectSortingStrategy}>
          <div className="grid grid-cols-3 sm:grid-cols-4 lg:grid-cols-5 gap-3">
            {images.map((url, index) => (
              <SortableImageItem
                key={url + '__' + index}
                url={url}
                index={index}
                isMain={index === 0}
                onRemove={() => onRemove(index)}
                totalImages={images.length}
              />
            ))}
          </div>
        </SortableContext>

        {/* Drag overlay — shows a floating copy of the dragged item */}
        <DragOverlay adjustScale>
          {activeId && activeIndex !== null ? (
            <div className="aspect-square rounded-xl overflow-hidden bg-[#111] border-2 border-[#0070f3] shadow-2xl shadow-[#0070f3]/20 w-[120px]">
              <Image
                src={images[activeIndex]}
                alt="Dragging"
                width={120}
                height={120}
                className="object-cover w-full h-full"
              />
            </div>
          ) : null}
        </DragOverlay>
      </DndContext>
    </div>
  )
}

'use client'

import { createContext, useContext, useEffect, useState, ReactNode, useCallback, useMemo } from 'react'
import Cookies from 'js-cookie'
import { useRouter } from 'next/navigation'

interface AdminAuthContextType {
  isAuthenticated: boolean
  isLoading: boolean
  login: (password: string) => Promise<boolean>
  logout: () => void
  token: string | null
}

const AdminAuthContext = createContext<AdminAuthContextType | undefined>(undefined)

const TOKEN_KEY = 'atelier_admin_token'

export function AdminAuthProvider({ children }: { children: ReactNode }) {
  const [isAuthenticated, setIsAuthenticated] = useState(false)
  const [token, setToken] = useState<string | null>(null)
  const [isLoading, setIsLoading] = useState(true)
  const router = useRouter()

  // eslint-disable-next-line react-hooks/set-state-in-effect
  useEffect(() => {
    const storedToken = Cookies.get(TOKEN_KEY)
    if (storedToken) {
      setToken(storedToken)
      setIsAuthenticated(true)
    }
    setIsLoading(false)
  }, [])

  const login = useCallback(async (password: string): Promise<boolean> => {
    try {
      const res = await fetch('/api/admin/login', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ username: 'admin', password })
      })

      if (res.ok) {
        const data = await res.json()
        Cookies.set(TOKEN_KEY, data.token, {
          expires: 1,
          secure: window.location.protocol === 'https:',
          sameSite: 'strict',
        })
        setToken(data.token)
        setIsAuthenticated(true)
        return true
      }
      return false
    } catch (e) {
      return false
    }
  }, [])

  const logout = useCallback(() => {
    Cookies.remove(TOKEN_KEY)
    setToken(null)
    setIsAuthenticated(false)
    router.push('/admin')
  }, [router])

  const contextValue = useMemo(() => ({
    isAuthenticated,
    isLoading,
    login,
    logout,
    token
  }), [isAuthenticated, isLoading, login, logout, token])

  return (
    <AdminAuthContext.Provider value={contextValue}>
      {children}
    </AdminAuthContext.Provider>
  )
}

export function useAdminAuth() {
  const context = useContext(AdminAuthContext)
  if (context === undefined) {
    throw new Error('useAdminAuth must be used within an AdminAuthProvider')
  }
  return context
}

'use client'

import { createContext, useContext, useEffect, useState, ReactNode, useCallback, useRef, useMemo } from 'react'
import { Product } from '@/lib/supabase'
import { useUserAuth } from './UserAuthContext'

interface FavoritesContextType {
  favorites: Product[]
  favoriteIds: Set<string>
  addFavorite: (product: Product) => Promise<void>
  removeFavorite: (productId: string) => Promise<void>
  isFavorite: (productId: string) => boolean
  loading: boolean
  refetch: () => Promise<void>
}

const FavoritesContext = createContext<FavoritesContextType | undefined>(undefined)

const TOKEN_KEY = 'atelier_client_token'
const FAVS_CACHE_KEY = 'atelier_favs_cache'
const FAVS_CACHE_TTL = 10 * 60 * 1000 // 10 minutes

function getClientToken(): string {
  if (typeof window === 'undefined') return ''

  let token = localStorage.getItem(TOKEN_KEY)
  if (!token) {
    if (typeof crypto !== 'undefined' && crypto.randomUUID) {
      token = crypto.randomUUID()
    } else {
      token = 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function (c) {
        const r = Math.random() * 16 | 0
        const v = c === 'x' ? r : (r & 0x3 | 0x8)
        return v.toString(16)
      })
    }
    localStorage.setItem(TOKEN_KEY, token)
  }
  return token
}

// Session-scoped favorites cache — avoids /api/favorites on every navigation
function getCachedFavorites(): Product[] | undefined {
  if (typeof window === 'undefined') return undefined
  try {
    const raw = sessionStorage.getItem(FAVS_CACHE_KEY)
    if (!raw) return undefined
    const parsed = JSON.parse(raw)
    if (parsed.ts && Date.now() - parsed.ts < FAVS_CACHE_TTL) {
      return parsed.data as Product[]
    }
    sessionStorage.removeItem(FAVS_CACHE_KEY)
  } catch { /* ignore */ }
  return undefined
}

function setCachedFavorites(data: Product[]) {
  if (typeof window === 'undefined') return
  try {
    sessionStorage.setItem(FAVS_CACHE_KEY, JSON.stringify({ data, ts: Date.now() }))
  } catch { /* quota exceeded */ }
}

function clearCachedFavorites() {
  if (typeof window === 'undefined') return
  try { sessionStorage.removeItem(FAVS_CACHE_KEY) } catch { /* ignore */ }
}

export function FavoritesProvider({ children }: { children: ReactNode }) {
  const [favorites, setFavorites] = useState<Product[]>([])
  const [favoriteIds, setFavoriteIds] = useState<Set<string>>(new Set())
  const [loading, setLoading] = useState(true)
  const { isAuthenticated, isLoading: authLoading } = useUserAuth()
  const fetchedRef = useRef(false)
  const prevAuthRef = useRef<boolean | null>(null)

  // Fetch favorites from API and cache
  const fetchFavorites = useCallback(async () => {
    setLoading(true)
    try {
      let res: Response
      if (isAuthenticated) {
        res = await fetch('/api/favorites', { credentials: 'include' })
      } else {
        const token = getClientToken()
        res = await fetch(`/api/favorites?client_token=${token}`)
      }

      if (res.ok) {
        const data: Product[] = await res.json()
        setFavorites(data)
        setFavoriteIds(new Set(data.map((p) => p.id)))
        setCachedFavorites(data)
      }
    } catch (error) {
      console.error('Failed to fetch favorites:', error)
    } finally {
      setLoading(false)
    }
  }, [isAuthenticated])

  // On mount or auth change: use cache if available, fetch only when needed
  useEffect(() => {
    if (authLoading) return

    const authChanged = prevAuthRef.current !== null && prevAuthRef.current !== isAuthenticated
    prevAuthRef.current = isAuthenticated

    if (authChanged) {
      // Auth state changed (login/logout) — clear stale cache and refetch
      clearCachedFavorites()
      fetchedRef.current = false
    }

    if (fetchedRef.current) return
    fetchedRef.current = true

    const cached = getCachedFavorites()
    if (cached !== undefined && !authChanged) {
      // Cache hit — skip API call
      setFavorites(cached)
      setFavoriteIds(new Set(cached.map((p) => p.id)))
      setLoading(false)
    } else {
      fetchFavorites()
    }
  }, [authLoading, isAuthenticated, fetchFavorites])

  const addFavorite = useCallback(async (product: Product) => {
    // Optimistic update
    setFavorites(prev => {
      const newFavs = [...prev, product]
      setCachedFavorites(newFavs)
      return newFavs
    })
    setFavoriteIds((prev) => new Set(prev).add(product.id))

    try {
      const body: Record<string, string> = { product_id: product.id }
      if (!isAuthenticated) {
        body.client_token = getClientToken()
      }

      const res = await fetch('/api/favorites', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        credentials: 'include',
        body: JSON.stringify(body),
      })

      if (!res.ok) {
        // Revert on error using functional update to avoid stale closures
        setFavorites(prev => {
          const reverted = prev.filter((p) => p.id !== product.id)
          setCachedFavorites(reverted)
          return reverted
        })
        setFavoriteIds((prev) => {
          const newSet = new Set(prev)
          newSet.delete(product.id)
          return newSet
        })
      }
    } catch (error) {
      console.error('Failed to add favorite:', error)
      setFavorites(prev => {
        const reverted = prev.filter((p) => p.id !== product.id)
        setCachedFavorites(reverted)
        return reverted
      })
      setFavoriteIds((prev) => {
        const newSet = new Set(prev)
        newSet.delete(product.id)
        return newSet
      })
    }
  }, [isAuthenticated])

  const removeFavorite = useCallback(async (productId: string) => {
    let removedProduct: Product | undefined

    // Optimistic update using functional state to avoid stale closures
    setFavorites(prev => {
      removedProduct = prev.find((p) => p.id === productId)
      const newFavs = prev.filter((p) => p.id !== productId)
      setCachedFavorites(newFavs)
      return newFavs
    })
    setFavoriteIds((prev) => {
      const newSet = new Set(prev)
      newSet.delete(productId)
      return newSet
    })

    try {
      const body: Record<string, string> = { product_id: productId }
      if (!isAuthenticated) {
        body.client_token = getClientToken()
      }

      const res = await fetch('/api/favorites', {
        method: 'DELETE',
        headers: { 'Content-Type': 'application/json' },
        credentials: 'include',
        body: JSON.stringify(body),
      })

      if (!res.ok && removedProduct) {
        // Revert on error
        const product = removedProduct
        setFavorites(prev => {
          const reverted = [...prev, product]
          setCachedFavorites(reverted)
          return reverted
        })
        setFavoriteIds((prev) => new Set(prev).add(productId))
      }
    } catch (error) {
      console.error('Failed to remove favorite:', error)
      if (removedProduct) {
        const product = removedProduct
        setFavorites(prev => {
          const reverted = [...prev, product]
          setCachedFavorites(reverted)
          return reverted
        })
        setFavoriteIds((prev) => new Set(prev).add(productId))
      }
    }
  }, [isAuthenticated])

  // Force-refetch clears cache so next call hits API
  const forceRefetch = useCallback(async () => {
    clearCachedFavorites()
    fetchedRef.current = false
    await fetchFavorites()
  }, [fetchFavorites])

  const isFavorite = (productId: string) => favoriteIds.has(productId)

  const contextValue = useMemo(() => ({
    favorites,
    favoriteIds,
    addFavorite,
    removeFavorite,
    isFavorite,
    loading,
    refetch: forceRefetch,
  }), [
    favorites,
    favoriteIds,
    addFavorite,
    removeFavorite,
    loading,
    forceRefetch,
  ])

  return (
    <FavoritesContext.Provider value={contextValue}>
      {children}
    </FavoritesContext.Provider>
  )
}

export function useFavorites() {
  const context = useContext(FavoritesContext)
  if (!context) {
    throw new Error('useFavorites must be used within a FavoritesProvider')
  }
  return context
}

