    }
    if (file.size > MAX_FILE_SIZE) {
      const sizeMB = (file.size / (1024 * 1024)).toFixed(1)
      return `"${file.name}" is ${sizeMB} MB — max is 8 MB`
    }
    return null
  }, [])

  /** Add files to the pending queue, returns validation errors */
  const addFiles = useCallback((files: File[], maxTotal: number): string[] => {
    const errors: string[] = []
    const valid: UploadItem[] = []

    for (const file of files) {
      const err = validateFile(file)
      if (err) {
        errors.push(err)
        continue
      }
      valid.push({
        id: `${Date.now()}-${Math.random().toString(36).slice(2, 8)}`,
        file,
        previewUrl: URL.createObjectURL(file),
        progress: 0,
        status: 'pending'
      })
    }

    setUploads(prev => {
      const remaining = maxTotal - prev.length
      if (valid.length > remaining) {
        errors.push(`Only ${remaining} more image(s) allowed (max ${maxTotal})`)
        return [...prev, ...valid.slice(0, remaining)]
      }
      return [...prev, ...valid]
    })

    return errors
  }, [validateFile])

  /** Upload a single file via signed URL */
  const uploadOne = useCallback(async (item: UploadItem): Promise<string> => {
    // 1. Get signed upload URL from our API
    const res = await fetch('/api/admin/upload-url', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        ...(token ? { Authorization: `Bearer ${token}` } : {})
      },
      body: JSON.stringify({
        filename: item.file.name,
        contentType: item.file.type,
        folder: 'products'
      })
    })

    if (!res.ok) {
      const body = await res.json().catch(() => ({}))
      throw new Error(body.error || 'Failed to get upload URL')
    }

    const { signedUrl, publicUrl, token: uploadToken } = await res.json()

    // 2. Upload directly to Supabase Storage with XHR for progress
    return new Promise<string>((resolve, reject) => {
      const xhr = new XMLHttpRequest()
      abortControllers.current.set(item.id, xhr)

      xhr.upload.addEventListener('progress', (e) => {
        if (e.lengthComputable) {
          const pct = Math.round((e.loaded / e.total) * 100)
          setUploads(prev =>
            prev.map(u => u.id === item.id ? { ...u, progress: pct } : u)
          )
        }
      })

      xhr.addEventListener('load', () => {
        abortControllers.current.delete(item.id)
        if (xhr.status >= 200 && xhr.status < 300) {
          resolve(publicUrl)
        } else {
          reject(new Error(`Upload failed (${xhr.status})`))
        }
      })

      xhr.addEventListener('error', () => {
        abortControllers.current.delete(item.id)
        reject(new Error('Network error during upload'))
      })

      xhr.addEventListener('abort', () => {
        abortControllers.current.delete(item.id)
        reject(new Error('Upload cancelled'))
      })

      // Supabase signed upload uses PUT with the token as a query param
      const url = signedUrl
      xhr.open('PUT', url)
      xhr.setRequestHeader('Content-Type', item.file.type)
      xhr.send(item.file)
    })
  }, [token])

  /** Start uploading all pending items */
  const uploadAll = useCallback(async (): Promise<string[]> => {
    const pending = uploads.filter(u => u.status === 'pending')
    if (!pending.length) return []

    // Mark all as uploading
    setUploads(prev =>
      prev.map(u => u.status === 'pending' ? { ...u, status: 'uploading', progress: 0 } : u)
    )

    const results: string[] = []

    for (const item of pending) {
      try {
        const publicUrl = await uploadOne(item)
        results.push(publicUrl)
        setUploads(prev =>
          prev.map(u => u.id === item.id ? { ...u, status: 'done', progress: 100, publicUrl } : u)
        )
      } catch (err: any) {
        setUploads(prev =>
          prev.map(u => u.id === item.id ? { ...u, status: 'error', error: err.message } : u)
        )
      }
    }

    return results
  }, [uploads, uploadOne])

  /** Remove a file from the queue and revoke its preview URL */
  const removeUpload = useCallback((id: string) => {
    setUploads(prev => {
      const item = prev.find(u => u.id === id)
      if (item) {
        URL.revokeObjectURL(item.previewUrl)
        // Abort if still uploading
        const xhr = abortControllers.current.get(id)
        if (xhr) xhr.abort()
      }
      return prev.filter(u => u.id !== id)
    })
  }, [])

  /** Clear all completed/errored uploads */
  const clearDone = useCallback(() => {
    setUploads(prev => {
      prev.filter(u => u.status === 'done' || u.status === 'error')
        .forEach(u => URL.revokeObjectURL(u.previewUrl))
      return prev.filter(u => u.status !== 'done' && u.status !== 'error')
    })
  }, [])

  /** Reset everything */
  const reset = useCallback(() => {
    uploads.forEach(u => URL.revokeObjectURL(u.previewUrl))
    abortControllers.current.forEach(xhr => xhr.abort())
    abortControllers.current.clear()
    setUploads([])
  }, [uploads])

  const isUploading = uploads.some(u => u.status === 'uploading')
  const pendingCount = uploads.filter(u => u.status === 'pending').length
  const totalProgress = uploads.length
    ? Math.round(uploads.reduce((sum, u) => sum + u.progress, 0) / uploads.length)
    : 0

  return {
    uploads,
    addFiles,
    uploadAll,
    removeUpload,
    clearDone,
    reset,
    isUploading,
    pendingCount,
    totalProgress,
    MAX_FILE_SIZE
  }
}

import { useState, useEffect, useCallback, useRef } from 'react'
import { Product } from '@/lib/supabase'

interface UseProductsOptions {
  category?: string
  gender?: string
  minPrice?: number
  maxPrice?: number
  limit?: number
  search?: string
}

/**
 * Client-side cache shared across all useProducts/useProduct instances.
 * Entries expire after CLIENT_CACHE_TTL so we don't show stale data
 * forever, but within the TTL window, navigation between pages is instant.
 */
const CLIENT_CACHE_TTL = 60_000 // 1 minute
const clientCache = new Map<string, { data: any; ts: number }>()

function getCached<T>(key: string): T | undefined {
  const entry = clientCache.get(key)
  if (entry && Date.now() - entry.ts < CLIENT_CACHE_TTL) return entry.data as T
  return undefined
}

function setCache<T>(key: string, data: T) {
  clientCache.set(key, { data, ts: Date.now() })
  // Evict old entries if cache grows too large
  if (clientCache.size > 200) {
    const oldest = clientCache.keys().next().value as string
    clientCache.delete(oldest)
  }
}

function makeKey(prefix: string, opts: Record<string, any>): string {
  const parts = Object.keys(opts)
    .filter(k => opts[k] !== undefined && opts[k] !== null && opts[k] !== '')
    .sort()
    .map(k => `${k}=${opts[k]}`)
    .join('&')
  return parts ? `${prefix}:${parts}` : prefix
}

export function useProducts(options: UseProductsOptions = {}) {
  const cacheKey = makeKey('products', options)
  const cachedData = getCached<Product[]>(cacheKey)

  // Initialize state from cache if available — no loading flicker
  const [products, setProducts] = useState<Product[]>(cachedData || [])
  const [loading, setLoading] = useState(!cachedData)
  const [error, setError] = useState<string | null>(null)
  const abortRef = useRef<AbortController | null>(null)

  const fetchProducts = useCallback(async () => {
    // Abort previous in-flight request
    abortRef.current?.abort()
    const controller = new AbortController()
    abortRef.current = controller

    // If we have cached data, show it immediately (no loading state)
    const cached = getCached<Product[]>(cacheKey)
    if (cached) {
      setProducts(cached)
      setLoading(false)
    } else {
      setLoading(true)
    }
    setError(null)

    const params = new URLSearchParams()
    if (options.category) params.set('category', options.category)
    if (options.gender) params.set('gender', options.gender)
    if (options.minPrice !== undefined) params.set('minPrice', String(options.minPrice))
    if (options.maxPrice !== undefined) params.set('maxPrice', String(options.maxPrice))
    if (options.limit) params.set('limit', String(options.limit))
    if (options.search) params.set('search', options.search)

    try {
      const res = await fetch(`/api/products?${params}`, { signal: controller.signal })
      if (!res.ok) throw new Error('Failed to fetch products')
      const data = await res.json()
      if (!controller.signal.aborted) {
        setProducts(data)
        setCache(cacheKey, data)
      }
    } catch (err) {
      if (err instanceof DOMException && err.name === 'AbortError') return
      if (!controller.signal.aborted) {
        setError(err instanceof Error ? err.message : 'Unknown error')
      }
    } finally {
      if (!controller.signal.aborted) setLoading(false)
    }
  }, [cacheKey, options.category, options.gender, options.minPrice, options.maxPrice, options.limit, options.search])

  useEffect(() => {
    fetchProducts()
    return () => abortRef.current?.abort()
  }, [fetchProducts])

  return { products, loading, error, refetch: fetchProducts }
}

export function useProduct(id: string | undefined) {
  const cacheKey = id ? `product:${id}` : ''
  const cachedData = id ? getCached<Product>(cacheKey) : undefined

  const [product, setProduct] = useState<Product | null>(cachedData || null)
  const [loading, setLoading] = useState(!cachedData && !!id)
  const [error, setError] = useState<string | null>(null)

  useEffect(() => {
    if (!id) {
      setLoading(false)
      return
    }

    const controller = new AbortController()

    // Show cached data immediately
    const cached = getCached<Product>(`product:${id}`)
    if (cached) {
      setProduct(cached)
      setLoading(false)
    } else {
      setLoading(true)
    }

    const fetchProduct = async () => {
      setError(null)

      try {
        const res = await fetch(`/api/products/${id}`, { signal: controller.signal })
        if (!res.ok) throw new Error('Product not found')
        const data = await res.json()
        if (!controller.signal.aborted) {
          setProduct(data)
          setCache(`product:${id}`, data)
        }
      } catch (err) {
        if (err instanceof DOMException && err.name === 'AbortError') return
        if (!controller.signal.aborted) {
          setError(err instanceof Error ? err.message : 'Unknown error')
        }
      } finally {
        if (!controller.signal.aborted) setLoading(false)
      }
    }

    // If we had cached data, still revalidate in background (stale-while-revalidate)
    fetchProduct()

    return () => controller.abort()
  }, [id])

  return { product, loading, error }
}

import { supabase } from './supabase'
