/**
 * Rate Limiter — Upstash Redis (serverless-safe)
 * ================================================
 * Uses @upstash/ratelimit with a sliding-window algorithm backed by
 * Upstash Redis.  Falls back to an in-memory Map when the env vars
 * UPSTASH_REDIS_REST_URL / UPSTASH_REDIS_REST_TOKEN are not set
 * (local dev / preview deploys).
 *
 * Required env vars for production:
 *   UPSTASH_REDIS_REST_URL
 *   UPSTASH_REDIS_REST_TOKEN
 */

import { Ratelimit } from '@upstash/ratelimit'
import { Redis } from '@upstash/redis'

// ── Upstash Redis singleton ──

let redis: Redis | null = null

function getRedis(): Redis | null {
  if (redis) return redis
  const url = process.env.UPSTASH_REDIS_REST_URL
  const token = process.env.UPSTASH_REDIS_REST_TOKEN
  if (!url || !token) return null
  redis = new Redis({ url, token })
  return redis
}

// ── In-memory fallback (dev / preview) ──
// Implements the minimal subset of the Redis interface that @upstash/ratelimit uses.

const memStore = new Map<string, { value: string; expireAt?: number }>()

function makeInMemoryRedis() {
  const store = memStore

  const self = {
    eval: undefined,
    evalsha: undefined,
    async hset(key: string, values: Record<string, unknown>) {
      const now = Date.now()
      const existing = store.get(key)
      const obj = existing && (!existing.expireAt || existing.expireAt > now)
        ? JSON.parse(existing.value)
        : {}
      for (const [k, v] of Object.entries(values)) obj[k] = v
      store.set(key, { value: JSON.stringify(obj), expireAt: existing?.expireAt })
      return 'OK'
    },
    async hgetall(key: string) {
      const entry = store.get(key)
      if (!entry) return null
      if (entry.expireAt && entry.expireAt <= Date.now()) { store.delete(key); return null }
      return JSON.parse(entry.value)
    },
    async expire(key: string, seconds: number) {
      const entry = store.get(key)
      if (entry) entry.expireAt = Date.now() + seconds * 1000
      return 1
    },
    async sadd(_key: string, ..._members: string[]) { return 0 },
    async multi() {
      const ops: (() => Promise<unknown>)[] = []
      const chain: any = {
        hset: (key: string, values: Record<string, unknown>) => { ops.push(() => self.hset(key, values)); return chain },
        expire: (key: string, s: number) => { ops.push(() => self.expire(key, s)); return chain },
        exec: async () => { const r = []; for (const fn of ops) r.push(await fn()); return r },
        hgetall: (key: string) => { ops.push(() => self.hgetall(key)); return chain },
      }
      return chain
    },
  }
  return self as unknown as ConstructorParameters<typeof Ratelimit>[0]['redis']
}

const inMemoryRedis = makeInMemoryRedis()

// ── Public API (drop-in replacement for old interface) ──

export interface RateLimitOptions {
  /** Time window in milliseconds */
  interval: number
  /** Max requests per window */
  maxRequests: number
}

// Cache Ratelimit instances per options-key so we don't recreate them
const limiters = new Map<string, Ratelimit>()

function getLimiter(options: RateLimitOptions): Ratelimit {
  const cacheKey = `${options.interval}:${options.maxRequests}`
  const existing = limiters.get(cacheKey)
  if (existing) return existing

  const r = getRedis()

  const limiter = new Ratelimit({
    redis: r ?? inMemoryRedis,                     // in-memory fallback for dev
    limiter: Ratelimit.slidingWindow(
      options.maxRequests,
      `${options.interval} ms` as any              // Upstash accepts ms duration
    ),
    analytics: false,
    prefix: 'rl',
  })

  limiters.set(cacheKey, limiter)
  return limiter
}

export function rateLimit(options: RateLimitOptions) {
  return {
    check: async (
      identifier: string
    ): Promise<{ success: boolean; remaining: number }> => {
      const limiter = getLimiter(options)
      const { success, remaining } = await limiter.limit(identifier)
      return { success, remaining }
    },
  }
}

// Helper to get client IP
export function getClientIp(req: any): string {
  return (
    req.headers['x-forwarded-for']?.split(',')[0].trim() ||
    req.headers['x-real-ip'] ||
    req.connection?.remoteAddress ||
    'unknown'
  )
}

// Re-export Redis singleton for other modules that may need it (e.g. cache)
export { getRedis }

/**
 * Multi-Layer Server Cache
 * ========================
 * A unified caching module for all server-side data fetching.
 *
 * Layers:
 *   L1 — In-memory Map with TTL (per API route / getStaticProps)
 *   L2 — Deduplication (in-flight promise sharing)
 *   L3 — Stale-while-revalidate (serve stale, refresh in background)
 *   L4 — ISR revalidation (Next.js page-level, external to this module)
 *   L5 — HTTP Cache-Control headers (CDN/browser, set by caller)
 *
 * Features:
 *   • Tag-based invalidation (e.g. invalidate all "products" entries at once)
 *   • Configurable TTL per entry
 *   • Max entries with LRU eviction
 *   • Dedup concurrent identical requests
 *   • Stale-while-revalidate: returns stale data immediately while refreshing
 *   • Type-safe generic API
 */

interface CacheEntry<T> {
  data: T
  timestamp: number
  tags: string[]
  lastAccessed: number
}

interface CacheOptions {
  /** Time-to-live in milliseconds */
  ttl: number
  /** Tags for group invalidation (e.g. ['products', 'listing']) */
  tags?: string[]
  /** Allow returning stale data while revalidating in background */
  staleWhileRevalidate?: boolean
  /** Extra time (ms) a stale entry is considered servable during background refresh */
  staleTTL?: number
}

const DEFAULT_MAX_ENTRIES = 500

class ServerCache {
  private cache = new Map<string, CacheEntry<any>>()
  private inflight = new Map<string, Promise<any>>()
  private maxEntries: number

  constructor(maxEntries = DEFAULT_MAX_ENTRIES) {
    this.maxEntries = maxEntries
  }

  /**
   * Get-or-fetch with full multi-layer logic.
   * If cached & fresh → return immediately (L1).
   * If another call for the same key is in-flight → share that promise (L2).
   * If staleWhileRevalidate & stale data exists → return stale, refresh in bg (L3).
   * Otherwise fetch, cache, return.
   */
  async getOrFetch<T>(
    key: string,
    fetcher: () => Promise<T>,
    options: CacheOptions
  ): Promise<{ data: T; hit: boolean }> {
    const { ttl, tags = [], staleWhileRevalidate = false, staleTTL } = options
    const now = Date.now()

    // L1: Fresh cache hit
    const entry = this.cache.get(key) as CacheEntry<T> | undefined
    if (entry && now - entry.timestamp < ttl) {
      entry.lastAccessed = now
      return { data: entry.data, hit: true }
    }

    // L3: Stale-while-revalidate — return stale, kick off bg refresh
    const effectiveStaleTTL = staleTTL ?? ttl * 2
    if (staleWhileRevalidate && entry && now - entry.timestamp < effectiveStaleTTL) {
      entry.lastAccessed = now
      // Background refresh (fire-and-forget)
      if (!this.inflight.has(key)) {
        this._backgroundRefresh(key, fetcher, ttl, tags)
      }
      return { data: entry.data, hit: true }
    }

    // L2: Dedup — share in-flight promise
    const existing = this.inflight.get(key)
    if (existing) {
      const data = await existing
      return { data, hit: false }
    }

    // Fetch, cache, return
    const promise = this._fetch(key, fetcher, ttl, tags)
    this.inflight.set(key, promise)

    try {
      const data = await promise
      return { data, hit: false }
    } finally {
      this.inflight.delete(key)
    }
  }

  /**
   * Synchronous check: is the key cached and fresh?
   */
  has(key: string, ttl: number): boolean {
    const entry = this.cache.get(key)
    return !!entry && Date.now() - entry.timestamp < ttl
  }

  /**
   * Synchronous get — returns undefined if missing or stale.
   */
  get<T>(key: string, ttl: number): T | undefined {
    const entry = this.cache.get(key) as CacheEntry<T> | undefined
    if (entry && Date.now() - entry.timestamp < ttl) {
      entry.lastAccessed = Date.now()
      return entry.data
    }
    return undefined
  }

  /**
   * Manually set a value in cache.
   */
  set<T>(key: string, data: T, options: CacheOptions): void {
    this._evictIfNeeded()
    const now = Date.now()
    this.cache.set(key, {
      data,
      timestamp: now,
      tags: options.tags || [],
      lastAccessed: now,
    })
  }

  /**
   * Invalidate a specific key.
   */
  invalidate(key: string): boolean {
    return this.cache.delete(key)
  }

  /**
   * Invalidate all entries matching a tag.
   * E.g. invalidateByTag('products') clears all product-related cache.
   */
  invalidateByTag(tag: string): number {
    let count = 0
    for (const [key, entry] of this.cache.entries()) {
      if (entry.tags.includes(tag)) {
        this.cache.delete(key)
        count++
      }
    }
    return count
  }

  /**
   * Invalidate all entries.
   */
  clear(): void {
    this.cache.clear()
    this.inflight.clear()
  }

  /**
   * Current cache size (for monitoring).
   */
  get size(): number {
    return this.cache.size
  }

  // ── Internal ──

  private async _fetch<T>(
    key: string,
    fetcher: () => Promise<T>,
    ttl: number,
    tags: string[]
  ): Promise<T> {
    const data = await fetcher()
    this._evictIfNeeded()
    const now = Date.now()
    this.cache.set(key, { data, timestamp: now, tags, lastAccessed: now })
    return data
  }

  private _backgroundRefresh<T>(
    key: string,
    fetcher: () => Promise<T>,
    ttl: number,
    tags: string[]
  ): void {
    const promise = fetcher()
      .then((data) => {
        const now = Date.now()
        this.cache.set(key, { data, timestamp: now, tags, lastAccessed: now })
      })
      .catch((err) => {
        console.error(`[ServerCache] Background refresh failed for key "${key}":`, err)
        // Keep stale data on failure
      })
      .finally(() => {
        this.inflight.delete(key)
      })
    this.inflight.set(key, promise)
  }

  private _evictIfNeeded(): void {
    if (this.cache.size < this.maxEntries) return

    // LRU eviction: remove the least-recently-accessed entry
    let oldestKey: string | null = null
    let oldestAccess = Infinity
    for (const [k, v] of this.cache.entries()) {
      if (v.lastAccessed < oldestAccess) {
        oldestAccess = v.lastAccessed
        oldestKey = k
      }
    }
    if (oldestKey) this.cache.delete(oldestKey)
  }
}

// ── Singleton instances ──

/** General-purpose server cache for API routes */
export const apiCache = new ServerCache(300)

/** SSG/ISR cache for getStaticProps data (smaller, long-lived) */
export const ssgCache = new ServerCache(100)

// ── Utility: sorted cache key ──

export function makeCacheKey(prefix: string, params: Record<string, any>): string {
  const sorted = Object.keys(params)
    .filter((k) => params[k] !== undefined && params[k] !== null && params[k] !== '')
    .sort()
    .map((k) => `${k}=${params[k]}`)
    .join('&')
  return sorted ? `${prefix}:${sorted}` : prefix
}

export { ServerCache }

import { supabase } from './supabase'

export interface ThemeColors {
    primary: string
    secondary: string
    accent: string
    text: string
    text_light: string
}

export interface NavMenuItem {
    id: string
    label: string
    href: string
}

export interface SiteConfig {
    id: string
    theme_colors: ThemeColors
    typography: any
    features: any
    homepage_layout: string[]
    nav_menu: NavMenuItem[]
    updated_at: string
}

let cachedConfig: SiteConfig | null = null
let cachedAt = 0
const CACHE_TTL = 5 * 60 * 1000 // 5 minutes
let fetchPromise: Promise<SiteConfig | null> | null = null

export async function getSiteConfig(): Promise<SiteConfig | null> {
    // If cached and still fresh, return it
    if (cachedConfig && Date.now() - cachedAt < CACHE_TTL) return cachedConfig

    // If a fetch is already in progress, wait for it
    if (fetchPromise) return fetchPromise

    fetchPromise = (async () => {
        try {
            const { data, error } = await supabase
                .from('site_config')
                .select('*')
                .single()

            if (error) {
                console.error('Error fetching site config:', error)
                return null
            }

            cachedConfig = data as SiteConfig
            cachedAt = Date.now()
            return cachedConfig
        } catch (e) {
            console.error('Unexpected error fetching site config:', e)
            return null
        } finally {
            // Always clear the promise so subsequent calls can refetch after TTL expires
            fetchPromise = null
        }
    })()

    return fetchPromise
}

export function clearSiteConfigCache() {
    cachedConfig = null
    fetchPromise = null
}

import jwt from 'jsonwebtoken'
import crypto from 'crypto'
import type { NextApiRequest, NextApiResponse } from 'next'
import type { NextRequest } from 'next/server'
import { getSupabaseAdmin } from './admin-api-utils'
import { verifyUserToken, type UserPayload } from './user-token'

// Re-export from lightweight module (no admin dependencies)
export { verifyUserToken, type UserPayload }

const isProduction = process.env.NODE_ENV === 'production'
if (isProduction && !process.env.USER_JWT_SECRET) {
  throw new Error('USER_JWT_SECRET environment variable is required in production')
}

const USER_JWT_SECRET = process.env.USER_JWT_SECRET || 'atelier-user-secret-key-change-in-production'
const USER_TOKEN_EXPIRY = '7d' // Users stay logged in longer than admins

/**
 * Generate a JWT token for a user
 */
export function generateUserToken(user: UserPayload): string {
  return jwt.sign(
    { id: user.id, email: user.email, name: user.name, role: 'user' },
    USER_JWT_SECRET,
    { expiresIn: USER_TOKEN_EXPIRY }
  )
}

/**
 * Extract user from request cookies
 */
export function getUserFromRequest(req: NextApiRequest): UserPayload | null {
  const token = req.cookies['atelier_user_token']
  if (!token) return null
  return verifyUserToken(token)
}

export function getUserFromNextRequest(req: NextRequest): UserPayload | null {
  const token = req.cookies.get('atelier_user_token')?.value
  if (!token) return null
  return verifyUserToken(token)
}

/**
 * Set user token as HTTP-only cookie
 */
export function setUserTokenCookie(res: NextApiResponse, token: string): void {
  // 7 days expiry
  const maxAge = 7 * 24 * 60 * 60
  res.setHeader(
    'Set-Cookie',
    `atelier_user_token=${token}; Path=/; HttpOnly; SameSite=Strict; Max-Age=${maxAge}${process.env.NODE_ENV === 'production' ? '; Secure' : ''}`
  )
}

export function buildUserTokenSetCookieHeader(token: string): string {
  const maxAge = 7 * 24 * 60 * 60
  return `atelier_user_token=${token}; Path=/; HttpOnly; SameSite=Strict; Max-Age=${maxAge}${process.env.NODE_ENV === 'production' ? '; Secure' : ''}`
}

/**
 * Clear user token cookie (logout)
 */
export function clearUserTokenCookie(res: NextApiResponse): void {
  res.setHeader(
    'Set-Cookie',
    `atelier_user_token=; Path=/; HttpOnly; SameSite=Strict; Max-Age=0`
  )
}

export function buildUserTokenClearCookieHeader(): string {
  return 'atelier_user_token=; Path=/; HttpOnly; SameSite=Strict; Max-Age=0'
}

/**
 * Generate a 6-digit OTP code using cryptographically secure randomness
 */
export function generateOtpCode(): string {
  return crypto.randomInt(100000, 999999).toString()
}

/**
 * Get OTP expiry time (10 minutes from now)
 */
export function getOtpExpiry(): Date {
  return new Date(Date.now() + 10 * 60 * 1000)
}

/**
 * Delete a user and set their order user_id references to NULL (preserve orders).
 * This ensures orders remain in the system for admin management while removing user data.
 * Returns true on success, false on failure (or if service role not configured).
 */
export async function deleteUserById(userId: string): Promise<boolean> {
  const supabase = getSupabaseAdmin()
  if (!supabase) return false

  try {
    // First, update orders to set user_id to NULL (preserve orders)
    const { error: ordersError } = await supabase
      .from('orders')
      .update({ user_id: null })
      .eq('user_id', userId)

    if (ordersError) {
      console.error('Failed to update orders user_id:', ordersError.message)
      return false
    }

    // Delete user-specific data (cart, favorites, etc.) - these will cascade
    const { error: cartError } = await supabase
      .from('user_cart')
      .delete()
      .eq('user_id', userId)

    if (cartError) {
      console.error('Failed to delete user cart:', cartError.message)
      // Continue anyway
    }

    const { error: favoritesError } = await supabase
      .from('user_favorites')
      .delete()
      .eq('user_id', userId)

    if (favoritesError) {
      console.error('Failed to delete user favorites:', favoritesError.message)
      // Continue anyway
    }

    // Look up the user's email to clean up their OTPs
    const { data: userData } = await supabase
      .from('users')
      .select('email')
      .eq('id', userId)
      .single()

    if (userData?.email) {
      const { error: otpError } = await supabase
        .from('user_otps')
        .delete()
        .eq('email', userData.email)
    }

    // Finally, delete the user record
    const { error } = await supabase.from('users').delete().eq('id', userId)
    if (error) {
      console.error('Failed to delete user:', error.message)
      return false
    }
    
    console.log(`User ${userId} deleted successfully. Orders preserved with user_id set to NULL.`)
    return true
  } catch (err) {
    console.error('Delete user error:', err)
    return false
  }
}

// Input validation and sanitization utilities

export function sanitizeEmail(email: string): string {
  return email.trim().toLowerCase()
}

export function isValidEmail(email: string): boolean {
  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/
  return emailRegex.test(email)
}

export function sanitizeString(input: string, maxLength: number = 1000): string {
  return input.trim().slice(0, maxLength)
}

export function isValidUUID(uuid: string): boolean {
  const uuidRegex = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i
  return uuidRegex.test(uuid)
}

export function sanitizeHtml(html: string): string {
  // Basic XSS prevention - remove script tags and event handlers
  return html
    .replace(/<script\b[^<]*(?:(?!<\/script>)<[^<]*)*<\/script>/gi, '')
    .replace(/on\w+\s*=\s*["'][^"']*["']/gi, '')
    .replace(/on\w+\s*=\s*[^\s>]*/gi, '')
}

export function validatePositiveNumber(value: any): number | null {
  const num = Number(value)
  if (isNaN(num) || num <= 0) return null
  return num
}

export function validateInteger(value: any, min?: number, max?: number): number | null {
  const num = parseInt(value, 10)
  if (isNaN(num)) return null
  if (min !== undefined && num < min) return null
  if (max !== undefined && num > max) return null
  return num
}

// SQL injection prevention for raw queries (use Supabase client instead when possible)
export function escapeSqlString(str: string): string {
  return str.replace(/'/g, "''")
}

const fs = require('fs');
const eslintOutput = JSON.parse(fs.readFileSync('eslint.json', 'utf8'));

let filesChanged = 0;

eslintOutput.forEach(file => {
    const errors = file.messages.filter(m => m.ruleId === '@typescript-eslint/no-explicit-any');
    if (errors.length > 0) {
        if (!fs.existsSync(file.filePath)) return;
        let content = fs.readFileSync(file.filePath, 'utf8');
        const lines = content.split('\n');

        const errorsByLine = {};
        errors.forEach(e => {
            if (!errorsByLine[e.line]) errorsByLine[e.line] = [];
            errorsByLine[e.line].push(e);
        });

        let changed = false;
        for (const [lineStr, lineErrors] of Object.entries(errorsByLine)) {
            const lineNum = parseInt(lineStr, 10);
            const lineIdx = lineNum - 1;

            if (lines[lineIdx] && lines[lineIdx].includes('unknown')) {
                // Revert naive changes on reported lines
                lines[lineIdx] = lines[lineIdx].replace(/:\s*unknown\b/g, ': any');
                lines[lineIdx] = lines[lineIdx].replace(/<\s*unknown\s*>/g, '<any>');
                changed = true;
            }
        }

        if (changed) {
            fs.writeFileSync(file.filePath, lines.join('\n'), 'utf8');
            filesChanged++;
        }
    }
});

console.log(`Reverted 'unknown' back to 'any' in ${filesChanged} files.`);
